import heapq

def solve(n: int, edges: list[list[int]]) -> int:
    adj = [[] for _ in range(n)]
    for u, v, s, e in edges:
        adj[u].append((v, s, e))

    dist = [float('inf')] * n
    dist[0] = 0
    heap = []
    heapq.heappush(heap, (0, 0))

    while heap:
        current_time, u = heapq.heappop(heap)
        if u == n - 1:
            return current_time
        if current_time > dist[u]:
            continue
        for v, s, e in adj[u]:
            earliest_time = max(current_time, s)
            if earliest_time <= e:
                arrival_time = earliest_time + 1
                if arrival_time < dist[v]:
                    dist[v] = arrival_time
                    heapq.heappush(heap, (arrival_time, v))

    return -1 if dist[n - 1] == float('inf') else dist[n - 1]
